    closed spec fn view(&self) -> OpArgsView {
        match self {
            OpArgs::Map { base, pte } => OpArgsView::Map { base: *base, pte: pte@ },
            OpArgs::Unmap { base } => OpArgsView::Unmap { base: *base },
        }
    }
}

